package main

import (
	"container/heap"
)

type State struct {
	cost     int64
	i, j     int
	remaining int64
}

type PriorityQueue []State

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}
func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(State))
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	x := old[n-1]
	*pq = old[0 : n-1]
	return x
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	dirs := [][]int{{0, 1}, {1, 0}}

	// Initialize distance matrix
	dist := make([][][]int64, m)
	for i := range dist {
		dist[i] = make([][]int64, n)
		for j := range dist[i] {
			dist[i][j] = make([]int64, k+1)
			for l := range dist[i][j] {
				dist[i][j][l] = 1 << 62
			}
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// Start at (0, 0) with k teleports left, initial cost is 0
	heap.Push(&pq, State{0, 0, 0, k})
	dist[0][0][k] = 0

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(State)
		cost, i, j, rem := current.cost, current.i, current.j, current.remaining

		if i == m-1 && j == n-1 {
			return cost
		}

		if cost > dist[i][j][rem] {
			continue
		}

		// Normal moves
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni < 0 || ni >= m || nj < 0 || nj >= n {
				continue
			}
			newCost := cost + grid[ni][nj]
			if newCost < dist[ni][nj][rem] {
				dist[ni][nj][rem] = newCost
				heap.Push(&pq, State{newCost, ni, nj, rem})
			}
		}

		// Teleport move if remaining teleports > 0
		if rem > 0 {
			for ni := 0; ni < m; ni++ {
				for nj := 0; nj < n; nj++ {
					if ni == i && nj == j {
						continue
					}
					if grid[ni][nj] > grid[i][j] {
						continue
					}
					if cost < dist[ni][nj][rem-1] {
						dist[ni][nj][rem-1] = cost
						heap.Push(&pq, State{cost, ni, nj, rem - 1})
					}
				}
			}
		}
	}

	return -1
}
