		dist[i] = make([][]int64, n)
		for j := range dist[i] {
			dist[i][j] = make([]int64, k+1)
			for l := range dist[i][j] {
				dist[i][j][l] = 1 << 60
			}
		}
	}

	heap.Push(&pq, &Item{0, 0, 0, k, 0})
	dist[0][0][k] = 0

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		cost, i, j, remK := item.cost, item.i, item.j, item.remK

		if i == m-1 && j == n-1 {
			return cost
		}

		if cost > dist[i][j][remK] {
			continue
